        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000419: ' + e.message };
        }
    },
    CHK0000420: function() {
        try {
            return ((function(checkDef, dateFilter) {
    // Check for any active Service Portal — CSM portal naming varies by org
